    order.status = new_status
    if side_effect_fn is not None:
        side_effect_fn(order, order.items)

    # Record the payment request
    payment = PaymentRequest(
        order_id=order.id,
        idempotency_key=idempotency_key,
        status='completed',
    )
    db.session.add(payment)
    db.session.commit()

