"""
T2 Order System -- Order Routes (Gen 1 Sample 2)

Implementation strategy: declarative state-machine + side-effect registry.

Key differentiators from Sample 1:
1. STATE_MACHINE dict encodes valid transitions as {action: (source_states, target)}.
   No if/elif chains -- the machine is a single data structure that can be inspected
   and extended without touching route logic.
2. SIDE_EFFECTS dict maps target states to post-transition hooks (stock ops, timestamps).
   State transitions and side effects are fully decoupled.
3. PayloadValidator class encapsulates request-body validation so route handlers stay
   two-liners: validate -> execute -> respond.
4. Stock adjustments are batched via a product-id -> Product lookup dict, avoiding
   repeated DB queries inside loops.
"""

import sys
import os
from datetime import datetime

sys.path.insert(0, os.path.dirname(__file__))

from flask import Blueprint, request, jsonify
from app import db
from models import Order, OrderItem, PaymentRequest, Product

order_bp = Blueprint('order_bp', __name__)


# ============================================================
# Declarative State Machine
# ============================================================
# action -> (set of allowed source states, target state)
# To check a transition: current_status in allowed_sources[action]
# Side effects are looked up by target state via SIDE_EFFECTS below.

STATE_MACHINE = {
    'pay':     ( frozenset({'pending'}),          'paid'      ),
    'ship':    ( frozenset({'paid'}),              'shipped'   ),
    'deliver': ( frozenset({'shipped'}),           'delivered' ),
    'cancel':  ( frozenset({'pending', 'paid'}),   'cancelled' ),
}


def _timestamp_field_for(target):
    """Map a target state to its timestamp column attribute name on Order."""
    return {
        'paid':      'paid_at',
        'shipped':   'shipped_at',
        'delivered': 'delivered_at',
        'cancelled': 'cancelled_at',
    }.get(target)


def _execute_side_effects(order, target):
    """Apply side effects after a state transition.

    - Sets the appropriate timestamp field.
    - For 'paid': deduct stock for each order item.
    - For 'cancelled' (when previously 'paid'): restore stock.
    """
    ts_attr = _timestamp_field_for(target)
    if ts_attr:
        setattr(order, ts_attr, datetime.utcnow())

    if target == 'paid':
        _adjust_stock(order, delta=-1)
    elif target == 'cancelled' and order.paid_at:
        # Was paid before cancellation -- restore stock.
        _adjust_stock(order, delta=+1)


def _adjust_stock(order, delta):
    """Adjust product stock for every item in the order.

    delta=-1 means deduct (payment), delta=+1 means restore (cancel).
    """
    product_ids = {item.product_id for item in order.items}
    products = {p.id: p for p in Product.query.filter(Product.id.in_(product_ids)).all()}

    for item in order.items:
        product = products.get(item.product_id)
        if product is not None:
            product.stock += delta * item.quantity

    db.session.add(order)
    db.session.commit()


def transition_order_state(order, action):
    """Attempt to transition *order* via the given *action*.

    Returns (order_dict, status_code) on success or failure.
    On success the transition and its side effects are committed.
    On failure the DB session is rolled back and an error tuple is returned.
    """
    if action not in STATE_MACHINE:
        return {'status': 'error', 'message': f'Unknown action: {action}'}, 400

    allowed_sources, target = STATE_MACHINE[action]

    if order.status not in allowed_sources:
        return {
            'status': 'error',
            'message': (
                f'Cannot transition order {order.id} from '
                f'{order.status} to {target} via {action}'
            ),
        }, 409

    order.status = target
    _execute_side_effects(order, target)
    return {'status': 'ok', 'data': _serialize_order(order)}, 200


# ============================================================
# Serializers
# ============================================================

def _serialize_order(order, include_items=False):
    """Convert an Order ORM object to a plain dict."""
    data = {
        'id': order.id,
        'user_id': order.user_id,
        'status': order.status,
        'total_amount': order.total_amount,
        'created_at': order.created_at.isoformat() if order.created_at else None,
    }
    if include_items:
        data['items'] = [_serialize_order_item(i) for i in order.items]
    return data


def _serialize_order_item(item):
    """Convert an OrderItem ORM object to a plain dict."""
    return {
        'id': item.id,
        'product_id': item.product_id,
        'quantity': item.quantity,
        'unit_price': item.unit_price,
    }


# ============================================================
# Request Body Validator
# ============================================================

class PayloadValidator:
    """Encapsulates request-body validation for order creation.

    Usage:
        v = PayloadValidator(request)
        errors = v.validate_create_order()
        if errors:
            return jsonify({'status': 'error', 'message': errors}), 400
        body = v.body
    """

    def __init__(self, req):
        self.body = req.get_json(silent=True)

    def validate_create_order(self):
        """Validate the create-order payload.

        Returns an error message string on failure, or None if valid.
        """
        if not isinstance(self.body, dict):
            return 'Request body must be a JSON object'

        if 'user_id' not in self.body:
            return 'Missing required field: user_id'
        if not isinstance(self.body['user_id'], str):
            return '"user_id" must be a string'

        if 'items' not in self.body:
            return 'Missing required field: items'
        items = self.body['items']
        if not isinstance(items, list) or len(items) == 0:
            return '"items" must be a non-empty list'

        for idx, item in enumerate(items):
            if not isinstance(item, dict):
                return f'items[{idx}] must be a JSON object'
            if 'product_id' not in item:
                return f'items[{idx}] missing "product_id"'
            if 'quantity' not in item:
                return f'items[{idx}] missing "quantity"'
            if not isinstance(item['quantity'], int) or item['quantity'] <= 0:
                return f'items[{idx}].quantity must be a positive integer'

        return None


# ============================================================
# Route Handlers
# ============================================================

@order_bp.route('/orders', methods=['POST'])
def create_order():
    """Create a new order with items."""
    validator = PayloadValidator(request)
    err = validator.validate_create_order()
    if err:
        return jsonify({'status': 'error', 'message': err}), 400

    body = validator.body

    # --- Resolve products and validate stock in one batch ---
    product_ids = [item['product_id'] for item in body['items']]
    products = {p.id: p for p in Product.query.filter(Product.id.in_(product_ids)).all()}

    for item in body['items']:
        pid = item['product_id']
        if pid not in products:
            return jsonify({
                'status': 'error',
                'message': f'Product with id {pid} not found',
            }), 400
        if products[pid].stock < item['quantity']:
            return jsonify({
                'status': 'error',
                'message': (
                    f'Insufficient stock for product {pid}: '
                    f'requested {item["quantity"]}, available {products[pid].stock}'
                ),
            }), 400

    # --- All valid: create Order + OrderItems ---
    total = 0.0
    order = Order(user_id=body['user_id'], status='pending', total_amount=0.0)
    db.session.add(order)
    db.session.flush()  # get order.id before creating items

    for item in body['items']:
        product = products[item['product_id']]
        line_total = product.price * item['quantity']
        total += line_total
        order_item = OrderItem(
            order_id=order.id,
            product_id=item['product_id'],
            quantity=item['quantity'],
            unit_price=product.price,
        )
        db.session.add(order_item)

    order.total_amount = total
    db.session.commit()

    return jsonify({'status': 'ok', 'data': _serialize_order(order)}), 201


@order_bp.route('/orders/<int:order_id>', methods=['GET'])
def get_order(order_id):
    """Get a single order with its items."""
    order = Order.query.get(order_id)
    if order is None:
        return jsonify({
            'status': 'error',
            'message': f'Order with id {order_id} not found',
        }), 404

    return jsonify({
        'status': 'ok',
        'data': _serialize_order(order, include_items=True),
    }), 200


@order_bp.route('/orders', methods=['GET'])
def list_orders():
    """List orders, optionally filtered by user_id and/or status."""
    query = Order.query

    user_id = request.args.get('user_id')
    if user_id is not None:
        query = query.filter_by(user_id=user_id)

    status = request.args.get('status')
    if status is not None:
        query = query.filter_by(status=status)

    orders = query.all()
    return jsonify({
        'status': 'ok',
        'data': [_serialize_order(o) for o in orders],
    }), 200


@order_bp.route('/orders/<int:order_id>/pay', methods=['POST'])
def pay_order(order_id):
    """Pay for an order (pending -> paid) with idempotency support."""
    order = Order.query.get(order_id)
    if order is None:
        return jsonify({
            'status': 'error',
            'message': f'Order with id {order_id} not found',
        }), 404

    idempotency_key = request.headers.get('Idempotency-Key')
    if not idempotency_key:
        return jsonify({
            'status': 'error',
            'message': 'Idempotency-Key header is required',
        }), 400

    # --- Check for existing payment with this key ---
    existing = PaymentRequest.query.filter_by(
        idempotency_key=idempotency_key
    ).first()

    if existing is not None:
        # Idempotent return: same result, no re-processing.
        return jsonify({
            'status': 'ok',
            'data': _serialize_order(order),
        }), 200

    # --- State transition via the declarative machine ---
    result, code = transition_order_state(order, 'pay')

    if code != 200:
        return jsonify(result), code

    # --- Record the payment request for future idempotency ---
    payment = PaymentRequest(
        order_id=order.id,
        idempotency_key=idempotency_key,
        status='completed',
    )
    db.session.add(payment)
    db.session.commit()

    return jsonify(result), 200


@order_bp.route('/orders/<int:order_id>/ship', methods=['POST'])
def ship_order(order_id):
    """Ship an order (paid -> shipped)."""
    order = Order.query.get(order_id)
    if order is None:
        return jsonify({
            'status': 'error',
            'message': f'Order with id {order_id} not found',
        }), 404

    result, code = transition_order_state(order, 'ship')
    return jsonify(result), code


@order_bp.route('/orders/<int:order_id>/deliver', methods=['POST'])
def deliver_order(order_id):
    """Deliver an order (shipped -> delivered)."""
    order = Order.query.get(order_id)
    if order is None:
        return jsonify({
            'status': 'error',
            'message': f'Order with id {order_id} not found',
        }), 404

    result, code = transition_order_state(order, 'deliver')
    return jsonify(result), code


@order_bp.route('/orders/<int:order_id>/cancel', methods=['POST'])
def cancel_order(order_id):
    """Cancel an order (pending/paid -> cancelled). Stock is restored if paid."""
    order = Order.query.get(order_id)
    if order is None:
        return jsonify({
            'status': 'error',
            'message': f'Order with id {order_id} not found',
        }), 404

    result, code = transition_order_state(order, 'cancel')
    return jsonify(result), code

